import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Quote: empty and simple base premiums ===
  it.todo("empty item list yields premium of 5 G (only processing fee)");
  it.todo("quote for a single plain sword yields 105 G (100 base + 5 fee)");
  it.todo("quote for a single plain amulet yields 65 G (60 base + 5 fee)");
  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");

  // === Components and building blocks ===
  it.todo("quote for 1 rune yields 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee)");
  it.todo("quote for 3 runes applies block: 65 G (60 base + 5 fee)");
  it.todo("quote for 4 runes does not apply block: 105 G (100 base + 5 fee)");
  it.todo("quote for 7 runes yields 180 G (175 base + 5 fee)");
  it.todo("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, no block)");
  it.todo("quote for 3 runes + 3 moonstones applies two blocks: 125 G (120 base + 5 fee)");

  // === Item-specific modifiers ===
  it.todo("cursed sword adds 50% of its base premium: 100 + 50 = 150 + 5 fee = 155 G");
  it.todo("highly enchanted sword (enchantment 5) adds 30%: 100 + 30 = 130 + 5 fee = 135 G");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge: 105 G");
  it.todo("cursed sword with enchantment 5 stacks both surcharges: 100 + 50 + 30 = 180 + 5 = 185 G");

  // === Policy-wide modifiers ===
  it.todo("loyalty discount applies for >=2 years: cursed sword + 3 yrs (no first-time, no follow-up): 100 + 50 - 20% = 120 + 5 = 125 G");
  it.todo("first insurance surcharge: 10% of policy base for new customer with single sword: 100 + 10 = 110 + 5 = 115 G");
  it.todo("follow-up contract discount: second quote for same customer applies 15% off");

  // === Multi-item modifier scope ===
  it.todo("cursed surcharge applies only to cursed item in a multi-item policy (sword cursed + plain amulet)");

  // === Newcomer with cursed sword integration example ===
  it.todo("newcomer (0 years) with cursed sword (steel, ench 3): premium 165 G");

  // === Long-standing customer's second contract integration example ===
  it.todo("3-year customer second quote with cursed sword ench 7: premium 160 G");

  // === Rounding ===
  it.todo("premium rounds up in MHPCO's favor");

  // === Claims: basic ===
  it.todo("claim: standard reimbursement on plain sword damage 500 G yields payout 400 G (deductible 100)");
  it.todo("claim: damage to a rune of 200 G yields payout 100 G");
  it.todo("claim: high-enchantment item (ench >= 8) reimburses 50% before deductible");
  it.todo("claim: dragon-material item is fully reimbursed (then deductible)");
  it.todo("claim: dragon material + ench 9 → 50% rule wins, then deductible");
  it.todo("claim: dragon material + ench 5 → only dragon clause applies");
  it.todo("claim: each damage entry has its own deductible (multi-item incident)");

  // === Claims: cap exhaustion ===
  it.todo("claim: payout per policy is capped at twice the insurance sum");
  it.todo("claim: cap is based on unmodified insurance value, not modified premium");
  it.todo("claim: block discount affects premium only, not insurance sum");
  it.todo("claim: successive claims deplete remaining cap");

  // === Multiple items of same type ===
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; both can be claimed");
  it.todo("claim: damages array with more entries of a type than the policy covers → error (CLI non-zero exit)");

  // === Payout rounding ===
  it.todo("payout rounds down in MHPCO's favor");

  // === Error handling ===
  it.todo("quote with unknown item type → error");
  it.todo("claim references damage for item not in the policy → error");
  it.todo("claim contains negative damage amount → error");
});

