      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("quote for a single plain amulet yields 65 G (60 base + 5 fee)");
  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");

  // === Components and building blocks ===
  it.todo("quote for 1 rune yields 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee)");
