const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsBasePremium = (items: Item[]): number => {
  const counts = new Map<string, number>();
  for (const it of items) {
    counts.set(it.type, (counts.get(it.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count - blocks * COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }
  return total;
};

const policyBasePremium = (items: Item[]): number => {
  const mainItems = items.filter((it) => !isComponent(it));
  const components = items.filter((it) => isComponent(it));
  const mainTotal = mainItems.reduce(
    (sum, it) => sum + (MAIN_ITEM_BASE_PREMIUM[it.type] ?? 0),
    0,
  );
  return mainTotal + componentsBasePremium(components);
};

const quoteStep = (step: QuoteStep): QuoteResult => {
  const policyBase = policyBasePremium(step.items);
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  const premium = policyBase + firstInsurance + PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
};

